	cl_int err = clGetPlatformIDs(0, NULL, &numPlatforms);
	if (err != CL_SUCCESS) {
		printf("No OpenCL platforms found.\n");
		return;
	}

	cl_platform_id* platforms = (cl_platform_id*)malloc(numPlatforms * sizeof(cl_platform_id));
	err = clGetPlatformIDs(numPlatforms, platforms, NULL);
	if (err != CL_SUCCESS) {
		free(platforms);
		return;
	}

	printf("Total Device found: %d\n", numPlatforms);

	for (cl_uint i = 0; i < numPlatforms; i++) {
		cl_uint numDevices;
		err = clGetDeviceIDs(platforms[i], CL_DEVICE_TYPE_ALL, 0, NULL, &numDevices);
		if (err != CL_SUCCESS) continue;

		cl_device_id* devices = (cl_device_id*)malloc(numDevices * sizeof(cl_device_id));
		err = clGetDeviceIDs(platforms[i], CL_DEVICE_TYPE_ALL, numDevices, devices, NULL);
		if (err != CL_SUCCESS) {
			free(devices);
			continue;
		}

		for (cl_uint j = 0; j < numDevices; j++) {
			char name[256], vendor[256];
			cl_ulong globalMem, sharedMem;
			cl_uint maxThreads;
			size_t maxDim[3];
