			clGetDeviceInfo(devices[j], CL_DEVICE_NAME, sizeof(name), name, NULL);
			clGetDeviceInfo(devices[j], CL_DEVICE_VENDOR, sizeof(vendor), vendor, NULL);
			clGetDeviceInfo(devices[j], CL_DEVICE_GLOBAL_MEM_SIZE, sizeof(globalMem), &globalMem, NULL);
			clGetDeviceInfo(devices[j], CL_DEVICE_LOCAL_MEM_SIZE, sizeof(sharedMem), &sharedMem, NULL);
			clGetDeviceInfo(devices[j], CL_DEVICE_MAX_WORK_GROUP_SIZE, sizeof(maxThreads), &maxThreads, NULL);
			clGetDeviceInfo(devices[j], CL_DEVICE_MAX_WORK_ITEM_sizes, sizeof(maxDim), maxDim, NULL);
			clGetDeviceInfo(devices[j], CL_DEVICE_CLOCK_FREQUENCY, sizeof(clockRate), &clockRate, NULL);

			printf("\nDevice Name \t\t - %s ", name);
			printf("\n**************************************");
			printf("\nTotal Global Memory\t\t\t - %lu KB", (unsigned long)(globalMem/1024));
			printf("\nShared memory available per block \t - %lu KB", (unsigned long)(sharedMem/1024));
			printf("\nNumber of registers per thread block \t - %d", 0);
			printf("\nWarp size in threads \t\t\t - %d", 0);
			printf("\nMemory Pitch \t\t\t\t - %zu bytes", 0);
			printf("\nMaximum threads per block \t\t - %d", maxThreads);
			printf("\nMaximum Thread Dimension (block) \t - %zu %zu %zu", maxDim[0], maxDim[1], maxDim[2]);
