void InitOpenCL() {
	if (context) return;

	cl_uint numPlatforms;
	cl_int err = clGetPlatformIDs(0, NULL, &numPlatforms);
	checkCLError("Getting platform count", err);

	cl_platform_id* platforms = (cl_platform_id*)malloc(numPlatforms * sizeof(cl_platform_id));
	err = clGetPlatformIDs(numPlatforms, platforms, NULL);
	checkCLError("Getting platform IDs", err);

	cl_device_id* devices = NULL;
	cl_uint numDevices = 0;

	for (cl_uint i = 0; i < numPlatforms; i++) {
		err = clGetDeviceIDs(platforms[i], CL_DEVICE_TYPE_ALL, 0, NULL, &numDevices);
		if (err == CL_SUCCESS && numDevices > 0) {
			devices = (cl_device_id*)malloc(numDevices * sizeof(cl_device_id));
			err = clGetDeviceIDs(platforms[i], CL_DEVICE_TYPE_ALL, numDevices, devices, NULL);
			if (err == CL_SUCCESS) break;
			free(devices);
			devices = NULL;
		}
	}

	if (!devices || numDevices == 0) {
		printf("No OpenCL devices found.\n");
		exit(1);
	}

	device_used = devices[0];

	context = clCreateContext(NULL, 1, &device_used, NULL, NULL, &err);
	checkCLError("Creating context", err);

	commandQueue = clCreateCommandQueue(context, device_used, 0, &err);
	checkCLError("Creating command queue", err);

	const char* source = 
		"__kernel void Fan1(float *m_cuda, float *a_cuda, int Size, int t) {\n"
		"    int idx = get_global_id(0);\n"
		"    if(idx >= Size-1-t) return;\n"
		"    m_cuda[Size*(idx+t+1)+t] = a_cuda[Size*(idx+t+1)+t] / a_cuda[Size*t+t];\n"
		"}\n"
		"__kernel void Fan2(float *m_cuda, float *a_cuda, float *b_cuda, int Size, int j1, int t) {\n"
		"    int xidx = get_global_id(0);\n"
		"    int yidx = get_global_id(1);\n"
		"    if(xidx >= Size-1-t) return;\n"
		"    if(yidx >= Size-t) return;\n"
		"    a_cuda[Size*(xidx+1+t)+(yidx+t)] -= m_cuda[Size*(xidx+1+t)+t] * a_cuda[Size*t+(yidx+t)];\n"
		"    if(yidx == 0){\n"
		"        b_cuda[xidx+1+t] -= m_cuda[Size*(xidx+1+t)+t] * b_cuda[t];\n"
		"    }\n"
		"}\n";

	program = clCreateProgramWithSource(context, 1, &source, NULL, &err);
	checkCLError("Creating program", err);

	err = clBuildProgram(program, 1, &device_used, NULL, NULL, NULL);
	if (err != CL_SUCCESS) {
		size_t log_size;
		clGetProgramBuildInfo(program, device_used, CL_PROGRAM_BUILD_LOG, 0, NULL, &log_size);
		char* log = (char*)malloc(log_size);
		clGetProgramBuildInfo(program, device_used, CL_PROGRAM_BUILD_LOG, log_size, log, NULL);
		printf("Build error: %s\n", log);
		free(log);
		exit(1);
	}

	kernelFan1 = clCreateKernel(program, "Fan1", &err);
	checkCLError("Creating kernel Fan1", err);
	kernelFan2 = clCreateKernel(program, "Fan2", &err);
	checkCLError("Creating kernel Fan2", err);

	free(devices);
	free(platforms);
}

void ForwardSub()
{
	int t;
    cl_mem m_cl, a_cl, b_cl;
	cl_int err;

	InitOpenCL();

	m_cl = clCreateBuffer(context, CL_MEM_READ_WRITE, Size * Size * sizeof(float), NULL, &err);
	checkCLError("Creating m buffer", err);
	a_cl = clCreateBuffer(context, CL_MEM_READ_WRITE, Size * Size * sizeof(float), NULL, &err);
	checkCLError("Creating a buffer", err);
	b_cl = clCreateBuffer(context, CL_MEM_READ_WRITE, Size * sizeof(float), NULL, &err);
	checkCLError("Creating b buffer", err);

	err = clEnqueueWriteBuffer(commandQueue, m_cl, CL_TRUE, 0, Size * Size * sizeof(float), m, 0, NULL, NULL);
	checkCLError("Writing m", err);
	err = clEnqueueWriteBuffer(commandQueue, a_cl, CL_TRUE, 0, Size * Size * sizeof(float), a, 0, NULL, NULL);
	checkCLError("Writing a", err);
	err = clEnqueueWriteBuffer(commandQueue, b_cl, CL_TRUE, 0, Size * sizeof(float), b, 0, NULL, NULL);
	checkCLError("Writing b", err);

	int block_size, grid_size;

	block_size = MAXBLOCKSIZE;
	if (block_size > Size) block_size = Size;
	grid_size = (Size + block_size - 1) / block_size;

	size_t global1 = (size_t)grid_size * block_size;
	size_t local1 = (size_t)block_size;

	int blockSize2d, gridSize2d;
	blockSize2d = BLOCK_SIZE_XY;
	if (blockSize2d > Size) blockSize2d = Size;
	gridSize2d = (Size + blockSize2d - 1) / blockSize2d; 

	size_t global2[2] = {(size_t)gridSize2d * blockSize2d, (size_t)gridSize2d * blockSize2d};
	size_t local2[2] = {(size_t)blockSize2d, (size_t)blockSize2d};

#ifdef  TIMING
	gettimeofday(&tv_kernel_start, NULL);
#endif


    struct timeval time_start;
    gettimeofday(&time_start, NULL);
	for (t=0; t<(Size-1); t++) {
		clSetKernelArg(kernelFan1, 0, sizeof(cl_mem), &m_cl);
		clSetKernelArg(kernelFan1, 1, sizeof(cl_mem), &a_cl);
		clSetKernelArg(kernelFan1, 2, sizeof(int), &Size);
		clSetKernelArg(kernelFan1, 3, sizeof(int), &t);
		err = clEnqueueNDRangeKernel(commandQueue, kernelFan1, 1, NULL, &global1, &local1, 0, NULL, NULL);
		checkCLError("Running Fan1", err);
		clFinish(commandQueue);

		int j1 = Size - t;
		clSetKernelArg(kernelFan2, 0, sizeof(cl_mem), &m_cl);
		clSetKernelArg(kernelFan2, 1, sizeof(cl_mem), &a_cl);
		clSetKernelArg(kernelFan2, 2, sizeof(cl_mem), &b_cl);
		clSetKernelArg(kernelFan2, 3, sizeof(int), &Size);
		clSetKernelArg(kernelFan2, 4, sizeof(int), &j1);
		clSetKernelArg(kernelFan2, 5, sizeof(int), &t);
		err = clEnqueueNDRangeKernel(commandQueue, kernelFan2, 2, NULL, global2, local2, 0, NULL, NULL);
		checkCLError("Running Fan2", err);
		clFinish(commandQueue);
	}

	struct timeval time_end;
    gettimeofday(&time_end, NULL);
    totalKernelTime = (time_end.tv_sec * 1000000 + time_end.tv_usec) - (time_start.tv_sec * 1000000 + time_start.tv_usec);

#ifdef  TIMING
	tvsub(&time_end, &tv_kernel_start, &tv);
	kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif


	err = clEnqueueReadBuffer(commandQueue, m_cl, CL_TRUE, 0, Size * Size * sizeof(float), m, 0, NULL, NULL);
	checkCLError("Reading m", err);
	err = clEnqueueReadBuffer(commandQueue, a_cl, CL_TRUE, 0, Size * Size * sizeof(float), a, 0, NULL, NULL);
	checkCLError("Reading a", err);
	err = clEnqueueReadBuffer(commandQueue, b_cl, CL_TRUE, 0, Size * sizeof(float), b, 0, NULL, NULL);
	checkCLError("Reading b", err);

	clReleaseMemObject(m_cl);
	clReleaseMemObject(a_cl);
	clReleaseMemObject(b_cl);
}






void BackSub()
{

	finalVec = (float *) malloc(Size * sizeof(float));

	int i,j;
	for(i=0;i<Size;i++){
		finalVec[Size-i-1]=b[Size-i-1];
		for(j=0;j<i;j++)
		{
			finalVec[Size-i-1]-=*(a+Size*(Size-i-1)+(Size-j-1)) * finalVec[Size-j-1];
		}
		finalVec[Size-i-1]=finalVec[Size-i-1]/ *(a+Size*(Size-i-1)+(Size-i-1));
	}
}

